import{_ as t,o,c as r,a4 as s}from"./chunks/framework.DiadTcoQ.js";const c=JSON.parse('{"title":"Pronoms et ordre des mots","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/pronouns-word-order.md","filePath":"module-2/pronouns-word-order.md"}'),a={name:"module-2/pronouns-word-order.md"};function n(d,e,m,l,u,i){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="pronoms-et-ordre-des-mots" tabindex="-1">Pronoms et ordre des mots <a class="header-anchor" href="#pronoms-et-ordre-des-mots" aria-label="Permalink to “Pronoms et ordre des mots”">​</a></h1><h2 id="les-pronoms-sujets" tabindex="-1">Les pronoms sujets <a class="header-anchor" href="#les-pronoms-sujets" aria-label="Permalink to “Les pronoms sujets”">​</a></h2><table tabindex="0"><thead><tr><th>Espagnol</th><th>Français</th></tr></thead><tbody><tr><td>yo</td><td>je</td></tr><tr><td>tú</td><td>tu</td></tr><tr><td>él / ella / usted</td><td>il / elle / vous (formel)</td></tr><tr><td>nosotros / nosotras</td><td>nous</td></tr><tr><td>vosotros / vosotras</td><td>vous (Espagne)</td></tr><tr><td>ellos / ellas / ustedes</td><td>ils / elles / vous (Amérique latine)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>En espagnol, le pronom sujet est souvent omis car la terminaison du verbe suffit à identifier la personne : <em>hablo</em> = je parle, <em>hablas</em> = tu parles.</p></div><div class="info custom-block"><p class="custom-block-title">usted / ustedes</p><p><strong>Usted</strong> (abrégé <strong>Ud.</strong>) est le vouvoiement formel. Il se conjugue comme la 3e personne du singulier. En Amérique latine, <strong>ustedes</strong> remplace <strong>vosotros</strong> pour le pluriel.</p></div><h2 id="l-ordre-des-mots" tabindex="-1">L&#39;ordre des mots <a class="header-anchor" href="#l-ordre-des-mots" aria-label="Permalink to “L&#39;ordre des mots”">​</a></h2><p>L&#39;ordre de base est <strong>Sujet — Verbe — Complément</strong>, comme en français.</p><blockquote><p><em>María come una manzana.</em> — María mange une pomme.</p></blockquote><p>Mais l&#39;espagnol est plus flexible. On peut inverser pour insister :</p><blockquote><p><em>Una manzana come María.</em> — C&#39;est une pomme que mange María.</p></blockquote><p><strong>Les adjectifs se placent généralement après le nom :</strong></p><blockquote><p><em>un coche rojo</em> — une voiture rouge <em>una casa grande</em> — une grande maison</p></blockquote><p>Certains adjectifs changent de sens selon leur position :</p><table tabindex="0"><thead><tr><th>Avant</th><th>Après</th></tr></thead><tbody><tr><td><em>un gran hombre</em> — un grand homme (remarquable)</td><td><em>un hombre grande</em> — un homme grand (physiquement)</td></tr><tr><td><em>mi viejo amigo</em> — mon vieil ami (de longue date)</td><td><em>un amigo viejo</em> — un ami vieux</td></tr></tbody></table>',14)])])}const h=t(a,[["render",n]]);export{c as __pageData,h as default};
